    18→pub fn serialize<T: Rapira>(item: &T) -> Vec<u8> {
    19→    let value_size = size(item);
    20→    let mut bytes: Vec<u8> = vec![0u8; value_size];
    21→    item.convert_to_bytes(&mut bytes, &mut 0);
    22→    bytes
    23→}
    24→
    25→/// extend vec of bytes with serialized object
    26→#[cfg(feature = "alloc")]
    27→pub fn extend_vec<T: Rapira>(item: &T, bytes: &mut Vec<u8>) {
    28→    let value_size = size(item);
    29→    let mut cursor = bytes.len();
    30→    bytes.resize(cursor + value_size, 0);
    31→    item.convert_to_bytes(bytes, &mut cursor);
    32→}
    33→
    34→/// write to vec of bytes with serialized object
    35→#[cfg(feature = "alloc")]
    36→pub fn write_to_vec<T: Rapira>(item: &T, bytes: &mut Vec<u8>) {
    37→    let value_size = size(item);
    38→    let len = bytes.len();
    39→    if len < value_size {
