    pub const fn static_size<T>(_: PhantomData<T>) -> Option<usize>
    where
        T: Sized,
    {
        Some(size_of::<T>())
    }

    pub const fn min_size<T>(_: PhantomData<T>) -> usize
    where
        T: Sized,
    {
