   180→        impl Rapira for $type {
   181→            const STATIC_SIZE: Option<usize> = Some(size_of::<$type>());
   182→            const MIN_SIZE: usize = size_of::<$type>();
   183→
   184→            #[inline]
   185→            fn from_slice(slice: &mut &[u8]) -> Result<Self>
   186→            where
   187→                Self: Sized,
   188→            {
   189→                let bytes: [u8; size_of::<$type>()] = into_arr(slice)?;
   190→                let u = <$type>::from_le_bytes(bytes);
   191→
   192→                *slice = &slice[size_of::<$type>()..];
   193→                Ok(u)
   194→            }
   195→
   196→            #[inline]
   197→            fn check_bytes(slice: &mut &[u8]) -> Result<()>
   198→            where
   199→                Self: Sized,
   200→            {
   201→                *slice = slice
   202→                    .get(size_of::<$type>()..)
   203→                    .ok_or(RapiraError::SliceLen)?;
   204→
   205→                Ok(())
   206→            }
   207→
   208→            #[inline]
   209→            unsafe fn from_slice_unsafe(slice: &mut &[u8]) -> Result<Self>
   210→            where
   211→                Self: Sized,
   212→            {
   213→                unsafe {
   214→                    let bytes: &[u8] = slice.get_unchecked(..size_of::<$type>());
   215→
   216→                    let arr: &[u8; size_of::<$type>()] = transmute_copy(&bytes);
   217→                    let u = <$type>::from_le_bytes(*arr);
   218→
   219→                    *slice = slice.get_unchecked(size_of::<$type>()..);
   220→                    Ok(u)
   221→                }
   222→            }
   223→
   224→            #[inline]
   225→            fn convert_to_bytes(&self, slice: &mut [u8], cursor: &mut usize) {
   226→                let bytes = self.to_le_bytes();
   227→                let end = *cursor + size_of::<$type>();
   228→                let s = &mut slice[*cursor..end];
   229→                s.copy_from_slice(&bytes);
   230→                *cursor = end;
   231→            }
   232→
   233→            #[inline]
   234→            fn try_convert_to_bytes(&self, slice: &mut [u8], cursor: &mut usize) -> Result<()> {
   235→                let bytes = self.to_le_bytes();
   236→                let end = *cursor + size_of::<$type>();
   237→                let s = slice.get_mut(*cursor..end).ok_or(RapiraError::SliceLen)?;
   238→                s.copy_from_slice(&bytes);
   239→                *cursor = end;
   240→                Ok(())
   241→            }
   242→
   243→            #[inline]
   244→            fn size(&self) -> usize {
   245→                size_of::<$type>()
   246→            }
   247→        }
   248→    };
   249→}
