   677→    #[inline]
   678→    fn from_slice(slice: &mut &[u8]) -> Result<Self>
   679→    where
   680→        Self: Sized,
   681→    {
   682→        let b = byte_rapira::from_slice(slice)?;
   683→        if b != 0 {
   684→            let t = T::from_slice(slice)?;
   685→            Ok(Some(t))
   686→        } else {
   687→            Ok(None)
   688→        }
   689→    }
