   691→    #[inline]
   692→    fn check_bytes(slice: &mut &[u8]) -> Result<()>
   693→    where
   694→        Self: Sized,
   695→    {
   696→        let b = byte_rapira::from_slice(slice)?;
   697→        if b != 0 {
   698→            T::check_bytes(slice)?;
   699→        }
   700→
   701→        Ok(())
   702→    }
