   704→    #[inline]
   705→    unsafe fn from_slice_unchecked(slice: &mut &[u8]) -> Result<Self>
   706→    where
   707→        Self: Sized,
   708→    {
   709→        let b = byte_rapira::from_slice(slice)?;
   710→        if b != 0 {
   711→            let t = unsafe { T::from_slice_unchecked(slice)? };
   712→            Ok(Some(t))
   713→        } else {
   714→            Ok(None)
   715→        }
   716→    }
   717→
   718→    #[inline]
   719→    unsafe fn from_slice_unsafe(slice: &mut &[u8]) -> Result<Self>
   720→    where
   721→        Self: Sized,
   722→    {
   723→        unsafe {
   724→            let b = byte_rapira::from_slice_unsafe(slice)?;
   725→            if b != 0 {
