   734→    #[inline]
   735→    fn try_convert_to_bytes(&self, slice: &mut [u8], cursor: &mut usize) -> Result<()> {
   736→        match self.as_ref() {
   737→            Some(s) => {
   738→                try_push(slice, cursor, 1)?;
   739→                s.try_convert_to_bytes(slice, cursor)?;
   740→            }
   741→            None => {
   742→                try_push(slice, cursor, 0)?;
   743→            }
   744→        }
   745→        Ok(())
