   749→    fn convert_to_bytes(&self, slice: &mut [u8], cursor: &mut usize) {
   750→        match self.as_ref() {
   751→            Some(s) => {
   752→                push(slice, cursor, 1);
   753→                s.convert_to_bytes(slice, cursor);
   754→            }
   755→            None => {
   756→                push(slice, cursor, 0);
   757→            }
   758→        }
   759→    }
