   762→impl<T: Rapira, E: Rapira> Rapira for Result<T, E> {
   763→    const STATIC_SIZE: Option<usize> = enum_size([T::STATIC_SIZE, E::STATIC_SIZE]);
   764→    const MIN_SIZE: usize = enum_min_size(&[T::MIN_SIZE, E::MIN_SIZE]);
   765→
   766→    #[inline]
   767→    fn size(&self) -> usize {
   768→        match self {
   769→            Ok(t) => 1 + t.size(),
   770→            Err(e) => 1 + e.size(),
   771→        }
   772→    }
   773→
   774→    #[inline]
   775→    fn check_bytes(slice: &mut &[u8]) -> Result<()>
   776→    where
   777→        Self: Sized,
   778→    {
   779→        let discriminant = byte_rapira::from_slice(slice)?;
   780→        match discriminant {
   781→            0 => T::check_bytes(slice),
   782→            1 => E::check_bytes(slice),
   783→            _ => Err(RapiraError::EnumVariant),
   784→        }
   785→    }
   786→
   787→    #[inline]
   788→    fn from_slice(slice: &mut &[u8]) -> Result<Self>
   789→    where
   790→        Self: Sized,
   791→    {
   792→        let discriminant = byte_rapira::from_slice(slice)?;
   793→        match discriminant {
   794→            0 => Ok(Ok(T::from_slice(slice)?)),
   795→            1 => Ok(Err(E::from_slice(slice)?)),
   796→            _ => Err(RapiraError::EnumVariant),
   797→        }
   798→    }
